INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(2, ' วัดคู่บ้านคู่เมืองของประเทศไทย และกรุงรัตนโกสินทร์ ก็คือที่นี่ค่ะ วัดพระศรีรัตนศาสดาราม หรือ วัดพระเเก้ว เป็นวัดในพระบรมมหาราชวังเช่นเดียวกับวัดพระศรีสรรเพชญ์ ซึ่งเป็นวัดในพระราชวังหลวงในสมัยอยุธยา\r\n\r\n      นอกจากนี้ภายในวัดพระศรีรัตนศาสดารามเป็นที่ประดิษฐาน พระพุทธมหามณีรัตนปฏิมากร หรือ พระแก้วมรกต ซึ่งอัญเชิญมามาจากกรุงเวียงจันทน์ เป็นวัดหลวงที่สำคัญในพระราชพิธีต่างๆ และยังเป็นแหล่งท่องเที่ยวที่สำคัญของประเทศไทยเราอีกด้วย', , 3, '2024-02-29 17:42:00.000000', 'วัดพระเเก้ว กรุงเทพฯ', 'วัด', 13, 'suporn');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(3, 'นอกจาก เชียงราย จะเป็นจังหวัดที่มีสถานที่ท่องเที่ยวชื่อดังอย่าง วัดร่องขุ่น บ้านดำ ดอยตุง แล้ว ที่นี่ยังเป็นอีกจังหวัดหนึ่งที่มีการทำไร่ชาตามแนวภูเขาค่ะ และแน่นอนว่าตรงจุดนี้เอง ทำให้เราเห็นวิวภูเขาสูงรายล้อมไร่ชาสีเขียวเป็นแนวยาว และฟ้าสีคราม\r\n\r\n     ไร่ชาฉุยฟง ตั้งอยู่ที่ อำเภอแม่จัน ค่ะ ที่นี่เป็นแหล่งปลูกชาชั้นดี และมีกิจกรรมให้นักท่องเที่ยวสามารถลงไปถ่ายรูปสวยๆ กับไร่ชาได้ ถ้ามาตอนเช้าหน่อยๆ ก็จะได้เห็นคุณป้า คุณอา มาเก็บยอดอ่อนใบชาด้วยนะ นอกจากนี้ ยังมีคาเฟ่ไว้ให้บริการคนที่มาเที่ยวอีกด้วย แน่นอนว่า ทุกอย่างในร้าน แทบจะมาจาก \"ชา\" ทั้งหมดเลยค่ะ', , 1, '2024-02-29 17:42:58.000000', 'ไร่ชาฉุยฟง เชียงราย', 'อื่นๆ', 1, 'พรทิ');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(5, 'หมู่เกาะกำ เป็นหมู่เกาะที่อยู่ในพื้นที่ของ อุทยานแห่งชาติแหลมสน จังหวัดระนอง ค่ะ ที่นี่เป็นหมู่เกาะที่มีความสวยงาม น้ำทะเลใส และหาดทรายขาว เป็นจุดดำน้ำตื้นและเล่นน้ำของเหล่านักท่องเที่ยวซึ่งสามารถไปเที่ยวที่นี่ได้ด้วยโปรแกรมนำเที่ยวหมู่เกาะกำแบบไปเช้าเย็นกลับ สามารถเช่าเหมาเรือหางยาวของชาวบ้าน ติดต่อขอเช่าเรือได้ที่ชมเรือนำเที่ยวค่ะ\r\n\r\n    เกาะที่ชาวเรือมักจะนิยมพานักท่องเที่ยวไปมีอยู่ 3 เกาะด้วยกัน ได้แก่ เกาะกำตก เกาะค้างคาว และเกาะญี่ปุ่น ซึ่งจริงๆ แล้วในหมู่เกาะกำยังมี เกาะกำนุ้ย และ เกาะกำใหญ่ อีกด้วย', , NULL, '2024-02-29 17:45:28.000000', 'หมู่เกาะกำ ระนอง', 'ทะเล', 1, 'ผกา');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(6, 'หลายคนที่ฝันอยากไปสัมผัสธรรมชาติ และเหมือนได้เดินอยู่ท่ามกลาง ทะเลหมอก และปุยเมฆ ภาพฝันนั้นเป็นจริงแล้วค่ะที่ สกายวอล์ค ทะเลหมอกอัยเยอร์เวง จุดชมทะเลหมอกเบตง จังหวัดยะลา ที่บอกเลยว่า ถ้าได้เห็นจะต้องเหมือนถูกมนต์สะกดเลยทีเดียว อีกทั้ง สกายวอล์ค ที่ยื่นยาวออกไปตั้งอยู่บนระดับความสูงกว่า 2,038 ฟุต พื้นทางเดินเป็นพื้นกระจกใส ยาว 61 เมตร ได้เดินออกไปบอกเลยว่า สวยแต่เสียว ไปตามๆ กัน', , NULL, '2024-02-29 17:46:17.000000', 'สกายวอล์ค ทะเลหมอกอัยเยอร์เวง', 'ภูเขา', 1, 'สุทธิ');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(7, 'ต้องบอกว่าหนึ่งปีมีแค่ครั้งเดียวเท่านั้นกับการอวดโฉมของ ซากุระเมืองไทย ที่ไม่ต้องบินไปไกลก็สามารถเที่ยวชมกันได้ที่ ดอยอ่างขาง ค่ะ ในช่วงที่ ดอกพญาเสือโคร่ง บานสะพรั่งตลอดสองข้างทางตามถนนที่ขึ้นไปยังดอยอ่างขางสองข้างทางที่คดเคี้ยวเลี้ยวลดไปมา จะแต่งแต้มไปด้วยสีชมพูหวาน เรียกได้ว่าสวยงามอลังการมากๆ นักท่องเที่ยวสามารถเดินชม ถ่ายรูปชิลๆ ตามจุดต่างๆ ได้\r\n\r\n    นอกจากนี้บนดอยอ่างขางยังเต็มไปด้วยสถานที่ท่องเที่ยวธรรมชาติที่สวยงามอื่นๆ มากมาย ทั้ง สถานีเกษตรหลวงอ่างขาง ไร่ชา 2000 ร่สตรอเบอร์รี่บ้านนอแล จุดชมวิวม่อนสน และอื่นๆ เพระาฉะนั้น บอกเลยว่า มาเที่ยวได้ตลอดทั้งปี', , NULL, '2024-02-29 17:51:42.000000', 'ดอยอ่างขาง เชียงใหม่', 'ภูเขา', 9, 'ดวงจันทร์');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(8, 'ลืมเมอร์ไลอ้อนสิงคโปร์ไปได้เลย! เพราะวันนี้เมืองไทยเรามีแลนด์มาร์คแห่งยโสธรคือ พิพิธภัณฑ์พญาคันคาก สุดยิ่งใหญ่ริมแม่น้ำทวน เป็นตึกพิพิธภัณฑ์รูปคางคก ความสูง 19 เมตร หรือเท่ากับตึก 5 ชั้นเลยทีเดียวค่ะ\r\n\r\n      สำหรับชาวอีสาน คางคกเป็นสัตว์ที่แสดงถึงความอุดมสมบูรณ์ของธรรมชาติ และเป็นตำนานความเชื่อเกี่ยวกับ ประเพณีบุญบั้งไฟ ที่มีมาช้านาน จึงเป็นที่มาของแลนด์มาร์คแห่งนี้ ที่ใครไปเที่ยวยโสธรก็ต้องแวะไปเช็คอิน', , NULL, '2024-02-29 17:52:27.000000', 'พิพิธภัณฑ์พญาคันคาก ยโสธร', 'พิพิธภัณฑ์', 1, 'มูมิน');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(9, 'อุทยานราชภักดิ์ หัวหิน ก่อสร้างโดยกองทัพบก สร้างขึ้นเพื่อน้อมรำลึกถึงคุณความดีของพระมหากษัตริย์ไทยในยุคก่อน โดยองค์รูปหล่อสำริดขนาด 13.9 เมตร ออกแบบโดยช่างจากกรมศิลปากร พระบรมราชานุสาวรีย์สมเด็จพระบูรพกษัตริย์แห่งสยาม 7 พระองค์ ได้แก่ พ่อขุนรามคำแหงมหาราช, สมเด็จพระนเรศวรมหาราช, สมเด็จพระนารายณ์มหาราช, สมเด็จพระเจ้าตากสินมหาราช, พระบาทสมเด็จพระพุทธยอดฟ้าจุฬาโลกมหาราช, พระบาทสมเด็จพระจอมเกล้าเจ้าอยู่หัว และพระบาทสมเด็จพระจุลจอมเกล้าเจ้าอยู่หัว', , NULL, '2024-02-29 17:53:05.000000', 'อุทยานราชภักดิ์ หัวหิน', 'อุทยานแห่งชาติ', 3, 'จีน่าแคนดี้');
INSERT INTO `blog` (`id`, `detail`, `image_data`, `like_count`, `post_date`, `title`, `type`, `view_count`, `writer`) VALUES
(10, 'วัดร่องขุ่น นี้ตั้งอยู่ที่ ตำบลป่าอ้อดอนชัย ห่างจากอำเภอเมืองเชียงรายไป 12 กิโลเมตรค่ะ ออกแบบและก่อสร้างโดย อาจารย์เฉลิมชัย โฆษิตพิพัฒน์ จิตรกรชื่อดังของไทย แรงบันดาลใจในการสร้างวัดแห่งนี้อยู่ 3 ประการ คือ เพื่อชาติ ศาสนา และพระมหากษัตริย์ เพื่อให้เป็นงานพุทธศิลป์ในรัชสมัยของพระบามสมเด็จพระเจ้าอยู่หัว รัชกาลที 9 นั่นเอง', , NULL, '2024-02-29 18:18:39.000000', 'วัดร่องขุ่น เชียงราย', 'วัด', 1, 'พรทิ');
