INSERT INTO `news` (`id`, `detail`, `image_data`, `post_date`, `title`, `writer`) VALUES
(1, 'คัลแลน พี่จอง ชื่อที่หลายคนกำลังค้นหา เขาคือสองหนุ่มชาวเกาหลีที่เปิดช่องยูทูบเปอร์เที่ยวไทยและพูดไทยตลอดเส้นทาง หลังจากเปิดช่องได้ไม่นาน ก็เป็นที่กล่าวถึงอย่างมากในโลกออนไลน์ จนยอดฟอลโลใกล้ล้านซับไปทุกที ครั้งนี้เราจึงขอพาทุกคนมาทำความรู้จักกับพวกเขาให้มากยิ่งขึ้น\r\n\r\nคัลแลน ตัดสินใจทำช่องยูทูปเพียงคนเดียว เพื่อรักษาความเป็นส่วนตัวให้กับสมาชิกในวง ขณะเดียวกับที่ยังคงรักษาความร่าเริงและสดใสของตัวเองไว้ นอกจากงานโปรดิวเซอร์และถ่ายแบบ คัลแลนกิน เที่ยว และเรียนรู้ภาษาไทยผ่านการใช้ชีวิตในเมืองไทย พร้อมชวนเพื่อน ๆ ที่รู้จักผลัดเปลี่ยนกันมาสนุกด้วยกัน เพื่อนร่วมวงสุดเท่อย่าง เคอร์บี้ ก็ร่วมอยู่ในช่องหลาย EP รวมถึง พี่จอง ที่ตอนนี้กลายเป็นยูทูบเบอร์คู่หูคัลแลนไปแล้วเรียบร้อย', , '2024-02-29 17:56:17.000000', 'รู้จัก คัลแลน พี่จอง สองยูทูบเบอร์เกาหลีพูดไทย พาเที่ยวไทยจนใจฟู', 'จองกุกกี้');

